create extension if not exists "pgcrypto";
create table if not exists public.owners(id uuid primary key default gen_random_uuid(),user_id uuid not null references auth.users(id) on delete cascade,surname text not null,name text,phone text,email text,created_at timestamptz not null default now());
create table if not exists public.patients(id uuid primary key default gen_random_uuid(),user_id uuid not null references auth.users(id) on delete cascade,owner_id uuid not null references public.owners(id) on delete cascade,name text not null,species text not null check(species in('Cane','Gatto','Furetto','Altro')),breed text,age_text text,sex text,neutered boolean,microchip text,main_diagnosis text,current_therapy text,next_control text,created_at timestamptz not null default now());
create table if not exists public.visits(id uuid primary key default gen_random_uuid(),user_id uuid not null references auth.users(id) on delete cascade,patient_id uuid not null references public.patients(id) on delete cascade,visit_date date not null default current_date,clinic text,weight_kg numeric(6,2),reason text,anamnesis text,clinical_exam text,conclusions text,notes_private text,created_at timestamptz not null default now());
create table if not exists public.exams(id uuid primary key default gen_random_uuid(),user_id uuid not null references auth.users(id) on delete cascade,visit_id uuid not null references public.visits(id) on delete cascade,exam_type text not null check(exam_type in('Ecocardiografia','ECG','Ecografia addominale','Holter','Altro')),report_text text,measurements jsonb not null default '{}'::jsonb,findings jsonb not null default '{}'::jsonb,created_at timestamptz not null default now());
alter table public.owners enable row level security;alter table public.patients enable row level security;alter table public.visits enable row level security;alter table public.exams enable row level security;
create policy owners_self on public.owners for all using(auth.uid()=user_id) with check(auth.uid()=user_id);
create policy patients_self on public.patients for all using(auth.uid()=user_id) with check(auth.uid()=user_id);
create policy visits_self on public.visits for all using(auth.uid()=user_id) with check(auth.uid()=user_id);
create policy exams_self on public.exams for all using(auth.uid()=user_id) with check(auth.uid()=user_id);
